INSERT INTO public.procurement_line_years (line_id, fiscal_year, service, appropriation, appr_code, ba, line_number, title, quantity, unit_cost, prior_year_actual, current_year_enacted, request_amount, fydp_yr1, fydp_yr2, fydp_yr3, fydp_yr4, narrative, content_hash, source_pdf, source_page, ingested_at) VALUES ($$PROC_AIRFOR_NA_L0055$$, 2027, $$Air Force$$, $$PROC_AIRFOR$$, $$AIRFOR$$, NULL, $$55$$, NULL, NULL, NULL, NULL, 216.227, NULL, NULL, NULL, 4.5, NULL, $$ set may not be exact or sum exactly due to rounding.

Justification:
FY27 procurement funding will concentrate on two major efforts: (1) complete the integration and testing of Baseline 15, and (2) continue the conversion of Baseline 13 aircraft into Baseline 15 aircraft. Nine
USAF RIVET JOINT aircraft are projected to receive the Baseline 14 configuration and eight USAF RIVET JOINT aircraft are projected to receive the Baseline 15 configuration. During this same period, COMBAT
SENT will start the conversion of a Baseline 5 aircraft to Baseline 15, and the COBRA BALL will continue integration and testing of Baseline 15. The COMBAT SENT and COBRA BALL baselines closely align
with RIVET JOINT Baseline 15. Additionally, FY27 procurement will ensure integration and fielding updates to the RC-135 ground systems, which include RIVET JOINT Ground Data Processing Systems
(GDPS), Distributed Mission Shelters (DMS), Mission Crew Training Systems (MCTS), Airborne Capabilities Extension System (ACES) and Operational Flight Trainers (OFT). The ground systems are upgraded
to remain consistent with the fielded aircraft configurations to allow for training and qualification of the aircrew and maintenance personnel assigned, plus verification and certification of software builds that are
continuously modified to address the dynamic mission requirements of these weapons systems.

Due to the changing threat and rapidly evolving near peer electromagnetic combat environment, the acquisition program manager has the authority to redirect funding as necessary to meet current and emerging
Combatant Commander and/or Intelligence Community requirements to better meet the war fighting objectives.




