INSERT INTO public.procurement_line_years (line_id, fiscal_year, service, appropriation, appr_code, ba, line_number, title, quantity, unit_cost, prior_year_actual, current_year_enacted, request_amount, fydp_yr1, fydp_yr2, fydp_yr3, fydp_yr4, narrative, content_hash, source_pdf, source_page, ingested_at) VALUES ($$PROC_AIRFOR_NA_L0036$$, 2027, $$Air Force$$, $$PROC_AIRFOR$$, $$AIRFOR$$, NULL, $$36$$, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, $$ set may not be exact or sum exactly due to rounding.

Justification:
Funding and budget data were revised to reflect execution actuals through FY 2026 and updated program office projections

FY 2027 funding supports, but is not limited to, the following efforts:

- EPAWSS Installation/modification
- SEPM: System Engineering/Program Management covering both the LRIP and FRP contracts, continued kit production management
- DMSMS: Monitoring and resolving Diminishing Manufacturing Sources/Material Shortages and/or obsolescence issues, DMS studies
- Production NRE: Software/operating system upgrades and applicable support equipment; efforts that increase maintenance data gathering capability, modernization efforts, trade studies
- Production Over & Above: Work discovered during modification that is not within EPAWSS scope but necessary to return aircraft to service
- ICS: Interim Contractor Support (ICS), to include Field Service Representatives (FSR), at operating locations
- CTR Repair Line Standup: Infrastructure investments to increase repair line capacity, thus avoiding impacts to concurrent hardware production
- Organic Install Tooling / Spt Equip: material required to maximize organic install capability at Warner Robins Air Logistics Complex
- SE/GFP Repair: Repair of Government Furnished Property (GFP); Supplemental tooling and support equipment (SE) for modification line and operating locations
- Data/Training: Updates to technical orders/manuals; technician and operator training
- OCCs/OGCs/PMA/ECOs: Program Office requirements and change orders




